//! SpecShakingMarker is an internal trait used to ensure that contract type specs
//! are included in the WASM binary when types are used at contract boundaries.
//!
//! The trait is called at three external boundary points:
//! 1. Contract function input parameters
//! 2. Contract function return values
//! 3. Event publishing
//!
//! Types that are only used internally (storage, cross-contract calls) do not
//! need their specs included, so the trait is NOT called from general TryFromVal
//! conversions.
//!
//! The trait has a default no-op implementation. Types generated by contracttype,
//! contractevent, and contracterror macros implement this trait to include their
//! spec XDR in the WASM's contractspecv0 section.
//!
//! Types whose layout includes their inner types inline (`Option<T>`,
//! `Result<T, E>`, tuples) call `T::spec_shaking_marker()` directly for
//! each inner type.
//!
//! Types whose size is independent of their inner types (`Vec<T>`,
//! `Map<K, V>`, `&T`, `&mut T`) use [`keep_reachable`] to reference each
//! inner type's marker without calling it. Recursive definitions are
//! possible through these types, so a direct call would risk a runtime cycle.

/// Trait for types that may include their spec in the WASM binary.
///
/// This trait is used internally by the SDK to ensure contract type specs
/// are included when types are used at external boundaries (function params,
/// return values, events).
///
/// Types with `#[contracttype]`, `#[contractevent]`, or `#[contracterror]`
/// will have implementations that include their spec. All other types have
/// a no-op implementation.
#[doc(hidden)]
pub trait SpecShakingMarker {
    /// Include this type's spec in the WASM binary.
    ///
    /// For primitive types and built-in SDK types, this is a no-op.
    /// For user-defined contract types, this ensures the spec XDR is
    /// included in the contractspecv0 section.
    #[inline(always)]
    fn spec_shaking_marker() {}
}

/// Keeps `f`'s symbol alive through the linker's dead-code-elimination
/// pass without invoking `f` at runtime. Takes `f` as a function pointer
/// and volatile-reads it. The same technique is used to keep the `MARKER`
/// byte statics alive (see `soroban-sdk-macros/src/shaking.rs`).
#[doc(hidden)]
#[inline(always)]
fn keep_reachable(f: fn()) {
    let _ = unsafe { core::ptr::read_volatile(&f) };
}

// Primitive type implementations (no-op)
impl SpecShakingMarker for () {}
impl SpecShakingMarker for bool {}
impl SpecShakingMarker for u32 {}
impl SpecShakingMarker for i32 {}
impl SpecShakingMarker for u64 {}
impl SpecShakingMarker for i64 {}
impl SpecShakingMarker for u128 {}
impl SpecShakingMarker for i128 {}

// Reference implementations — use `keep_reachable` because &T is
// pointer-sized independent of T, so recursive definitions through
// references could be possible. Currently, limitations of generics
// within `map_type` prevent this from working, so this is done
// out of caution.
impl<T: SpecShakingMarker> SpecShakingMarker for &T {
    #[inline(always)]
    fn spec_shaking_marker() {
        keep_reachable(T::spec_shaking_marker);
    }
}

impl<T: SpecShakingMarker> SpecShakingMarker for &mut T {
    #[inline(always)]
    fn spec_shaking_marker() {
        keep_reachable(T::spec_shaking_marker);
    }
}

// Option implementation - includes inner type's spec
impl<T: SpecShakingMarker> SpecShakingMarker for Option<T> {
    #[inline(always)]
    fn spec_shaking_marker() {
        T::spec_shaking_marker();
    }
}

// Result implementation - includes both types' specs
impl<T: SpecShakingMarker, E: SpecShakingMarker> SpecShakingMarker for Result<T, E> {
    #[inline(always)]
    fn spec_shaking_marker() {
        T::spec_shaking_marker();
        E::spec_shaking_marker();
    }
}

